def compute(inputs):
    no_of_shares = inputs["no_of_shares"]
    old_market_price = inputs["old_market_price"]
    new_market_price = inputs["new_market_price"]
    npv = (new_market_price - old_market_price) * no_of_shares / 1000000
    return round(npv)
